INSERT INTO `task` VALUES (7,'2026-06-01 16:44:46','2026-06-02 02:08:01','A + B',2.000,128,'Вводятся два целых числа, каждое с новой строки. Нужно вывести их сумму.','a = int(input())\r\nb = int(input())\r\n\r\nprint(a + b)','# a = int(input())\r\n# b = int(input())',800,'**Вход:**\r\n2\r\n3\r\n**Выход:**\r\n5',1,NULL,NULL,1,'{\"tests\": [{\"input\": \"5\\n6\", \"number\": 1, \"public\": true, \"expected\": \"11\"}, {\"input\": \"10\\n15\", \"number\": 2, \"public\": true, \"expected\": \"25\"}, {\"input\": \"-3\\n7\", \"number\": 3, \"public\": false, \"expected\": \"4\"}, {\"input\": \"0\\n0\", \"number\": 4, \"public\": false, \"expected\": \"0\"}, {\"input\": \"100\\n-50\", \"number\": 5, \"public\": false, \"expected\": \"50\"}]}'),(8,'2026-06-01 17:07:43','2026-06-01 17:07:43','Четное число',2.000,128,'Дано целое число ```n```. Определите, является ли оно четным. Если число четное, выведите ***YES***, иначе выведите ***NO***.','n = int(input())\r\nif n % 2 == 0:\r\n    print(\'YES\')\r\nelse:\r\n    print(\'NO\')','# n = int(input())',800,'**Вход:**\r\n12\r\n**Выход:**\r\nYES\r\n\r\n**Вход:**\r\n11\r\n**Выход:**\r\nNO',1,NULL,NULL,1,'{\"tests\": [{\"input\": \"8\", \"number\": 1, \"public\": true, \"expected\": \"YES\"}, {\"input\": \"7\", \"number\": 2, \"public\": true, \"expected\": \"NO\"}, {\"input\": \"0\", \"number\": 3, \"public\": false, \"expected\": \"YES\"}, {\"input\": \"-4\", \"number\": 4, \"public\": false, \"expected\": \"YES\"}, {\"input\": \"-9\", \"number\": 5, \"public\": false, \"expected\": \"NO\"}]}'),(9,'2026-06-01 17:10:14','2026-06-01 17:10:14','Большее из двух чисел',2.000,128,'Даны два целых числа ```a``` и ```b```. Напишите программу, которая выводит большее из них. Если числа равны, выведите любое из них.','a = int(input())\r\nb = int(input())\r\n\r\nprint(max(a,b))','# a = int(input())\r\n# b = int(input())',800,'**Вход:**\r\n2\r\n3\r\n**Выход:**\r\n3 \r\n\r\n**Вход:**\r\n-10\r\n12\r\n**Выход:**\r\n12',1,NULL,NULL,1,'{\"tests\": [{\"input\": \"12\\n7\", \"number\": 1, \"public\": true, \"expected\": \"12\"}, {\"input\": \"3\\n9\", \"number\": 2, \"public\": true, \"expected\": \"9\"}, {\"input\": \"5\\n5\", \"number\": 3, \"public\": false, \"expected\": \"5\"}, {\"input\": \"-2\\n-8\", \"number\": 4, \"public\": false, \"expected\": \"-2\"}, {\"input\": \"0\\n-1\", \"number\": 5, \"public\": false, \"expected\": \"0\"}]}'),(11,'2026-06-01 17:15:01','2026-06-01 17:15:01','Количество положительных чисел',2.000,128,'Дан список из целых чисел. Нужно посчитать, сколько чисел в списке являются положительными. Положительным считается число, которое больше нуля.\r\n\r\n***Входные данные***\r\n\r\nВ первой строке вводится число ```n``` — количество элементов списка.\r\nВо второй строке вводятся ```n``` целых чисел через пробел.\r\n\r\n***Выходные данные***\r\n\r\nВыведите количество положительных чисел.','n = int(input())\r\narr = list(map(int, input().split()))\r\n\r\ncount = 0\r\nfor i in range(len(arr)):\r\n    if 0 < arr[i]:\r\n        count += 1\r\n\r\nprint(count)','# n = int(input())\r\n# arr = list(map(int, input().split()))',800,'**Вход:**\r\n3\r\n1 2 3\r\n**Выход:**\r\n3\r\n\r\n**Вход:**\r\n3\r\n-1 -2 -3\r\n**Выход:**\r\n0',1,NULL,NULL,1,'{\"tests\": [{\"input\": \"5\\n-2 4 0 7 -1\", \"number\": 1, \"public\": true, \"expected\": \"2\"}, {\"input\": \"4\\n1 2 3 4\", \"number\": 2, \"public\": true, \"expected\": \"4\"}, {\"input\": \"3\\n-1 -2 -3\", \"number\": 3, \"public\": false, \"expected\": \"0\"}, {\"input\": \"5\\n0 0 0 0 0\", \"number\": 4, \"public\": false, \"expected\": \"0\"}, {\"input\": \"6\\n10 -5 3 -1 8 0\", \"number\": 5, \"public\": false, \"expected\": \"3\"}]}'),(12,'2026-06-01 17:17:09','2026-06-01 17:17:09','Сумма чисел от 1 до N',2.000,128,'Дано натуральное число ```n```. Напишите программу, которая вычисляет сумму всех чисел от 1 до ```n```.','n = int(input())\r\n\r\nsum = 0\r\nfor i in range(n + 1):\r\n    sum += i\r\n\r\nprint(sum)','# n = int(input())',800,'**Вход:**\r\n5\r\n**Выход:**\r\n15',1,NULL,NULL,1,'{\"tests\": [{\"input\": \"5\", \"number\": 1, \"public\": true, \"expected\": \"15\"}, {\"input\": \"1\", \"number\": 2, \"public\": true, \"expected\": \"1\"}, {\"input\": \"10\", \"number\": 3, \"public\": false, \"expected\": \"55\"}, {\"input\": \"100\", \"number\": 4, \"public\": false, \"expected\": \"5050\"}, {\"input\": \"50\", \"number\": 5, \"public\": false, \"expected\": \"1275\"}]}'),(13,'2026-06-02 01:10:07','2026-06-02 01:10:07','Последняя цифра числа',2.000,128,'Дано неотрицательное целое число ```n```. Напишите программу, которая выводит последнюю цифру этого числа.','n = int(input())\r\n\r\nprint(n % 10)','# n = int(input())',800,'**Вход:**\r\n2\r\n**Выход:**\r\n2\r\n\r\n**Вход:**\r\n10\r\n**Выход:**\r\n0\r\n\r\n**Вход:**\r\n11231\r\n**Выход:**\r\n1',1,NULL,NULL,1,'{\"tests\": [{\"input\": \"123\", \"number\": 1, \"public\": true, \"expected\": \"3\"}, {\"input\": \"45\", \"number\": 2, \"public\": true, \"expected\": \"5\"}, {\"input\": \"100\", \"number\": 3, \"public\": false, \"expected\": \"0\"}, {\"input\": \"7\", \"number\": 4, \"public\": false, \"expected\": \"7\"}, {\"input\": \"0\", \"number\": 5, \"public\": false, \"expected\": \"0\"}]}'),(15,'2026-06-02 01:15:25','2026-06-02 01:15:25','Сколько раз встречается число',1.000,128,'Дан список из ```n``` целых чисел и число ```x```. Нужно определить, сколько раз число x встречается в списке.\r\n\r\n***Входные данные***\r\nВ первой строке вводится число ```n```.\r\nВо второй строке вводятся ```n``` целых чисел через пробел.\r\nВ третьей строке вводится число ```x```.\r\n\r\n***Выходные данные***\r\nВыведите количество элементов списка, равных ```x```.','n = int(input())\r\narr = list(map(int, input().split()))\r\nx = int(input())\r\n\r\ncount = 0\r\nfor i in range(len(arr)):\r\n    if arr[i] == x:\r\n        count += 1\r\n\r\nprint(count)','# n = int(input())\r\n# arr = list(map(int, input().split()))\r\n# x = int(input())',800,'**Вход:**\r\n5\r\n1 2 3 2 4\r\n2\r\n**Выход:**\r\n2',1,NULL,NULL,1,'{\"tests\": [{\"input\": \"5\\n1 2 3 2 4\\n2\", \"number\": 1, \"public\": true, \"expected\": \"2\"}, {\"input\": \"4\\n1 1 1 1\\n1\", \"number\": 2, \"public\": true, \"expected\": \"4\"}, {\"input\": \"5\\n1 2 3 4 5\\n6\", \"number\": 3, \"public\": false, \"expected\": \"0\"}, {\"input\": \"6\\n0 -1 0 2 0 3\\n0\", \"number\": 4, \"public\": false, \"expected\": \"3\"}, {\"input\": \"1\\n10\\n10\", \"number\": 5, \"public\": false, \"expected\": \"1\"}]}'),(17,'2026-06-02 01:21:02','2026-06-02 01:21:02','Самое короткое слово',2.000,128,'Дана строка, состоящая из слов, разделенных пробелами. Нужно вывести самое короткое слово. Если таких слов несколько, выведите первое из них.','str = input()\r\nstrs = str.split()\r\n\r\nmin_str = strs[0]\r\nfor i in range(len(strs)):\r\n    if len(strs[i]) < len(min_str):\r\n        min_str = strs[i]\r\n\r\nprint(min_str)','# str = input()',800,'**Вход:**\r\npython is very simple\r\n**Выход:**\r\nis',1,NULL,NULL,1,'{\"tests\": [{\"input\": \"python is very simple\", \"number\": 1, \"public\": true, \"expected\": \"is\"}, {\"input\": \"one two three\", \"number\": 2, \"public\": true, \"expected\": \"one\"}, {\"input\": \"hello world\", \"number\": 3, \"public\": false, \"expected\": \"hello\"}, {\"input\": \"a bb ccc dddd\", \"number\": 4, \"public\": false, \"expected\": \"a\"}, {\"input\": \"school programming task\", \"number\": 5, \"public\": false, \"expected\": \"task\"}, {\"input\": \"test\", \"number\": 6, \"public\": false, \"expected\": \"test\"}]}');
/*!40000 ALTER TABLE `task` ENABLE KEYS */;
UNLOCK TABLES;

